const rawItems = $input.all();
const listaConsolidada = [];

// Expresión regular para validar que la fila empiece con un año de 4 dígitos
const regexAnio = /^\d{4}/;

for (const item of rawItems) {
  const data = item.json;
  const anioRaw = data.__EMPTY ? data.__EMPTY.toString().trim() : "";

  // FILTRO INTELIGENTE: Si no empieza con año, es basura
  if (!regexAnio.test(anioRaw)) {
    continue;
  }

  const pibRealMillones = parseFloat(data.__EMPTY_1);
  const poblacion = parseFloat(data.__EMPTY_2);
  const pibPcRealUsd = parseFloat(data.__EMPTY_3);
  const tasaVariacion = parseFloat(data.__EMPTY_4);

  listaConsolidada.push({
    json: {
      INDICADOR: "PIB_REAL_PER_CAPITA",
      FECHA_FISCAL: anioRaw,         // ◄--- NUEVA: El año como clave primaria lógica
      FECHA_EXTRACCION: new Date(),   // Objeto Date nativo corregido
      ESTADO: "COMPLETO",
      NECESITA_RESPALDO: 0,           // Tipo número corregido
      DETALLE_ERROR: "",
      DATOS_JSON: JSON.stringify({
        fecha_fiscal: anioRaw, 
        pib_real_millones: isNaN(pibRealMillones) ? null : pibRealMillones,
        poblacion_total: isNaN(poblacion) ? null : poblacion,
        pib_pc_real_usd: isNaN(pibPcRealUsd) ? null : pibPcRealUsd,
        tasa_variacion_anual: isNaN(tasaVariacion) ? null : tasaVariacion,
        fuente: "Banco Central del Ecuador",
        ruta_logica: "BCE/CUENTAS_NACIONALES/PIB_PC_REAL"
      })
    }
  });
}

return listaConsolidada;

