const rawItems = $input.all();
const listaConsolidada = [];

function parsearNumeroExcel(val) {
  if (val === undefined || val === null || val === '') return null;
  if (typeof val === 'number') return val;
  const limpio = val.toString().replace(/,/g, '').trim();
  const num = parseFloat(limpio);
  return isNaN(num) ? null : num;
}

for (const item of rawItems) {
  const data = item.json;

  const seccionCiiu = data.__EMPTY ? data.__EMPTY.toString().trim() : "";
  const cie = data.__EMPTY_1 ? data.__EMPTY_1.toString().trim() : "";
  const industria = data.__EMPTY_2 ? data.__EMPTY_2.toString().trim() : "";

  if (!industria || industria === "Industria" || industria.includes("Puestos de trabajo")) {
    continue;
  }

  // Generamos un identificador único para la industria que quepa en VARCHAR2(50)
  const idIndustriaClave = (cie || industria).substring(0, 50);

  if (industria === "Total Empleo") {
    listaConsolidada.push({
      json: {
        INDICADOR: "MEI_TOTAL_EMPLEO_NUR",
        FECHA_FISCAL: idIndustriaClave, // ◄--- NUEVA: Evita duplicar esta industria horizontal
        FECHA_EXTRACCION: new Date(),
        ESTADO: "COMPLETO",
        NECESITA_RESPALDO: 0,
        DETALLE_ERROR: "",
        DATOS_JSON: JSON.stringify({
          seccion_ciiu: seccionCiiu,
          cie: cie,
          industria: industria,
          valores_anuales: {
            2018: parsearNumeroExcel(data.__EMPTY_3),
            2019: parsearNumeroExcel(data.__EMPTY_4),
            2020: parsearNumeroExcel(data.__EMPTY_5),
            2021: parsearNumeroExcel(data.__EMPTY_6),
            2022: parsearNumeroExcel(data.__EMPTY_7),
            2023: parsearNumeroExcel(data.__EMPTY_8),
            2024: parsearNumeroExcel(data.__EMPTY_9)
          },
          fuente: "Banco Central del Ecuador",
          ruta_logica: "BCE/CUENTAS_NACIONALES/MEI_TOTAL_EMPLEO"
        })
      }
    });
    break; 
  }

  listaConsolidada.push({
    json: {
      INDICADOR: "MEI_EMPLEO_SECTORIAL",
      FECHA_FISCAL: idIndustriaClave,   // ◄--- NUEVA: Mapeo por sector
      FECHA_EXTRACCION: new Date(),
      ESTADO: "COMPLETO",
      NECESITA_RESPALDO: 0,
      DETALLE_ERROR: "",
      DATOS_JSON: JSON.stringify({
        seccion_ciiu: seccionCiiu,
        cie: cie,
        industria: industria,
        valores_anuales: {
          2018: parsearNumeroExcel(data.__EMPTY_3),
          2019: parsearNumeroExcel(data.__EMPTY_4),
          2020: parsearNumeroExcel(data.__EMPTY_5),
          2021: parsearNumeroExcel(data.__EMPTY_6),
          2022: parsearNumeroExcel(data.__EMPTY_7),
          2023: parsearNumeroExcel(data.__EMPTY_8),
          2024: parsearNumeroExcel(data.__EMPTY_9)
        },
        fuente: "Banco Central del Ecuador",
        ruta_logica: "BCE/CUENTAS_NACIONALES/MEI_TOTAL_EMPLEO"
      })
    }
  });
}

return listaConsolidada;

